namespace Spectre.Console;

internal static class Cell
{
    private const sbyte Sentinel = -2;

    /// <summary>
    /// UnicodeCalculator.GetWidth documents the width as (-1, 0, 1, 2). We only need space for these values and a sentinel for uninitialized values.
    /// This is only five values in total so we are storing one byte per value. We could store 2 per byte but that would add more logic to the retrieval.
    /// We should add one to char.MaxValue because the total number of characters includes \0 too so there are 65536 valid chars.
    /// </summary>
    private static readonly sbyte[] _runeWidthCache = new sbyte[char.MaxValue + 1];

    static Cell()
    {
#if !NETSTANDARD2_0
        Array.Fill(_runeWidthCache, Sentinel);
#else
        for (var i = 0; i < _runeWidthCache.Length; i++)
        {
            _runeWidthCache[i] = Sentinel;
        }
#endif
    }

    public static int GetCellLength(string text)
    {
        var sum = 0;
        foreach (var element in EnumerateTextElements(text))
        {
            sum += element.CellLength;
        }

        return sum;
    }

    public static int GetCellLength(ReadOnlySpan<char> text)
    {
        if (text.Length == 1)
        {
            return GetCellLength(text[0]);
        }

        return GetCellLength(text.ToString());
    }

    public static int GetCellLength(char rune)
    {
        // TODO: We need to figure out why Segment.SplitLines fails
        // if we let wcwidth (which returns -1 instead of 1)
        // calculate the size for new line characters.
        // That is correct from a Unicode perspective, but the
        // algorithm was written before wcwidth was added and used
        // to work with string length and not cell length.
        if (rune == '\n')
        {
            return 1;
        }

        var width = _runeWidthCache[rune];
        if (width == Sentinel)
        {
            width = (sbyte)UnicodeCalculator.GetWidth(rune);
            _runeWidthCache[rune] = width;
        }

        return width;
    }

    internal static IEnumerable<(string Text, int CellLength)> EnumerateTextElements(string text)
    {
        if (string.IsNullOrEmpty(text))
        {
            yield break;
        }

        var enumerator = System.Globalization.StringInfo.GetTextElementEnumerator(text);
        while (enumerator.MoveNext())
        {
            var element = enumerator.GetTextElement();
            yield return (element, GetTextElementCellLength(element));
        }
    }

    private static int GetTextElementCellLength(string text)
    {
        if (text.Length == 1)
        {
            return GetCellLength(text[0]);
        }

        var width = 0;
        var codePointCount = 0;
        var regionalIndicatorCount = 0;
        var hasWideCodePoint = false;
        var hasZeroWidthJoiner = false;
        var hasVariationSelector = false;
        var hasEmojiModifier = false;
        var hasTag = false;

        for (var index = 0; index < text.Length; index++)
        {
            var codePoint = char.ConvertToUtf32(text, index);
            var codePointWidth = GetCellLength(text[index]);
            if (char.IsHighSurrogate(text[index]) && index + 1 < text.Length)
            {
                index++;
                codePointWidth += GetCellLength(text[index]);
            }

            width += codePointWidth;
            codePointCount++;
            hasWideCodePoint |= codePointWidth >= 2;
            hasZeroWidthJoiner |= codePoint == 0x200D;
            hasVariationSelector |= codePoint == 0xFE0F;
            hasEmojiModifier |= codePoint is >= 0x1F3FB and <= 0x1F3FF;
            hasTag |= codePoint is >= 0xE0020 and <= 0xE007F;

            if (codePoint is >= 0x1F1E6 and <= 0x1F1FF)
            {
                regionalIndicatorCount++;
            }
        }

        if (regionalIndicatorCount > 1 && regionalIndicatorCount == codePointCount)
        {
            return 2;
        }

        if (hasWideCodePoint && (hasZeroWidthJoiner || hasEmojiModifier || hasTag))
        {
            return 2;
        }

        if (hasVariationSelector)
        {
            return Math.Max(2, width);
        }

        return width;
    }
}

